\begin{theorem}[cf.~Fitting and Mendelsohn~\cite{FM98}]
The quantified modal logic $\QK$ is Kripke complete.
That is, for any modal sentence $A$, the following are equivalent:
\begin{enumerate}
    \item $\QK \vdash A$. 
    \item $A$ is valid in all Kripke frames.
\end{enumerate}
\end{theorem}

